'use client';
  
  import { Canvas, useFrame } from '@react-three/fiber';
  import { OrbitControls } from '@react-three/drei';
  import { useRef } from 'react';
  import * as THREE from 'three';
  
  const Orb = () => {
    const ref = useRef<THREE.Mesh>(null!);
    useFrame((state) => {
      const t = state.clock.getElapsedTime();
      ref.current.rotation.x = t * 0.3;
      ref.current.rotation.y = t * 0.45;
    });
  
    return (
      <mesh ref={ref} castShadow receiveShadow>
        <sphereGeometry args={[1.3, 64, 64]} />
        <meshStandardMaterial
          metalness={0.85}
          roughness={0.25}
          color="#D6A75E"
          emissive="#8FAF9F"
          emissiveIntensity={0.4}
        />
      </mesh>
    );
  };
  
  export const LabScene = () => {
    return (
      <div className="relative h-[480px] overflow-hidden rounded-3xl border border-white/5 bg-gradient-to-b from-black/60 via-black/90 to-black">
        <Canvas
          shadows
          camera={{ position: [0, 0, 4.5], fov: 45 }}
        >
          <color attach="background" args={['#050506']} />
          <ambientLight intensity={0.25} />
          <spotLight
            position={[5, 8, 4]}
            angle={0.5}
            intensity={1.4}
            penumbra={0.8}
            castShadow
            color="#D6A75E"
          />
          <pointLight position={[-4, -3, -2]} intensity={0.7} color="#8FAF9F" />
          <Orb />
          <OrbitControls
            enablePan={false}
            enableZoom={false}
            autoRotate
            autoRotateSpeed={0.6}
          />
        </Canvas>
        <div className="pointer-events-none absolute inset-x-0 bottom-0 bg-gradient-to-t from-background/95 via-background/70 to-transparent" />
        <div className="pointer-events-none absolute inset-x-0 top-0 h-24 bg-gradient-to-b from-background/80 via-background/20 to-transparent" />
        <div className="absolute inset-x-6 bottom-6 flex flex-wrap items-center justify-between gap-3 text-xs text-neutral-300">
          <div>
            <p className="text-[11px] uppercase tracking-[0.2em] text-neutral-400">
              Spatial systems lab
            </p>
            <p className="mt-1 max-w-md text-neutral-200">
              Exploring calm, cinematic motion and light-weight 3D interfaces suitable
              for production-grade products.
            </p>
          </div>
        </div>
      </div>
    );
  };
  